code.C:
#include <stdio.h>
int main() {
    int T, x;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &x) != 1) break;
        if (x >= 10 && x <= 20) {
            printf("In Range\n");
        } else {
            printf("Out of Range\n");
        }
    }
    return 0;
}

